import React, { useEffect, useState } from 'react';
import { Layout, Col, Typography } from 'antd';

const { Footer } = Layout,
      { Link } = Typography;

export default function AdityaFooter() {
  const [widthHeader, setwidthHeader] = useState(window.innerWidth);

  useEffect(() => {
    const handleResize = () => {
      setwidthHeader(window.innerWidth)
    }

    window.addEventListener('resize', handleResize)
  }, [])

  return (
    <Footer className="AdityaFooter">
      <Col span={(widthHeader > 900) ? 12 : 24} offset={(widthHeader > 900) ? 6 : 0} style={{ textAlign: 'center' }}>
        <div style={{ fontSize: 16}}>
          © 2022 <Link href="/" style={{ color: 'rgba(0, 0, 0, 0.85)' }}>Aditya Adam F.</Link> All rights reserved.</div>
      </Col>
    </Footer>
  )
}