import React from 'react';
import ReactDOM from 'react-dom';
import $ from 'jquery';
import { Home, About, Portfolio, NotFound } from './../Component/Body';
import LoadingWeb from './../Component/Loading';

const SITES = 'https://adityaadamf.github.io';

document.addEventListener('DOMContentLoaded', function(e) {
  getPages(window.location.href.replace(SITES,''),2);
});

window.onpopstate = function historyback() {
  getPages(window.location.href.replace(SITES,''),2);
};

$(document).on('click','a', function(e) {
  let links = $(this).attr('href'),
      target = $(this).attr('target');

  if(links !== '#') {
    (links.substring(0,1) === '/') ? getPages(links,1) : window.open(links,target)
  }
  
  return false;
});

export const getPages = (request,type) => {
  let pages;
  (request === '/') ? pages = 'home' : pages = encodeURIComponent(request.substring(1))
  
  if(type === 2) { 
    $('body').addClass('loadweb')

    ReactDOM.render(
      <LoadingWeb />,
      document.body.appendChild(document.createElement('div'))
    );
  }

  document.body.scrollTop = 0;
  document.documentElement.scrollTop = 0;

  const getData = async () => {
    await fetch('/data/pages.json')
    .then(res => res.json())
    .then(result => {
      const getTrue = [], data = [];
      for(let i = 0; i < result.pages.length; i++) {
        getTrue.push(Object.values(result.pages[i]).includes(pages))
        if(Object.values(result.pages[i]).includes(pages)) {
          data.push({
            key: result.pages[i].key,
            title: result.pages[i].title,
            description: result.pages[i].description,
            author: 'Aditya Adam Firdaus'
          })
        }
      }
      if(Object.values(getTrue).includes(true)) {
        document.title = data[0].title;
        document.getElementsByTagName('meta')[3].content = data[0].description;
        document.getElementsByTagName('meta')[4].content = data[0].author;
      }else{
        document.title = 'Page Not Found';
        document.getElementsByTagName('meta')[3].content = 'Page Not Found';
        document.getElementsByTagName('meta')[4].content = 'Aditya Adam Firdaus';
      }

      if(type === 2) { 
        $('body').removeClass('loadweb')
        $('body').removeAttr('class')
        $('body > div:last-child').remove()
      }

      ReactDOM.render(
        <>
          {(data.length > 0 && listContent(data[0].key) !== undefined) ?
            listContent(data[0].key)
          :
            <NotFound key={Math.random()} />
          }
        </>,
        document.getElementsByClassName('AdityaContent')[0]
      );
    });
  };

  getData();

  if(request !== window.location.pathname) {
    if(pages === 'home' && type === 1) {
      window.history.pushState({'html':'/','pageTitle':document.title},'', '/')
    }else if(pages !== 'home' && type === 1) {
      window.history.pushState({prevUrl: window.location.href,'html':request,'pageTitle':document.title},'', request)
    }
  }
};

const listContent = (key) => {
  const list = {
    home: <Home key={key} />, 
    about: <About key={key} />, 
    portfolio: <Portfolio key={key} />
  }

  return list[key];
}