import React, { useEffect, useState } from "react";
import { Layout, Typography, Result, 
         Button, Row, Col, 
         Avatar, Space, Card, 
         List, Timeline, Breadcrumb } from 'antd';
import { TwitterOutlined, LinkedinFilled, GithubOutlined, 
         MailOutlined, HomeOutlined } from '@ant-design/icons';
import { getPages } from '../Tools/Connector';

const { Content } = Layout,
      { Title, Link, Paragraph } = Typography;

const data = {
  home: [
    ["Aditya Adam Firdaus","Coder, Programmer and Analyst","/assets/img/aditya.jpg"],
    {
      personal: [
        "Personal Details",
        `My background is Bachelor of Statistics from Bandung Islamic University. 
         Interested with Coding, Programming and Analysis. 
         Love Machine Learning with favorite algorithms XGBoost and LightGBM.
         I am adaptable and propensity to learn something the new about analytics or coding.`
      ]
    },
    {
      skills: {
        title: "Skills"
      }
    },
    {
      activity: {
        title: "My Latest Activities"
      }
    }
  ],
  about: [
    [
      "Aditya Adam Firdaus",
      "/assets/img/aditya.jpg",
      {
        desc: [
          `At Beginning Autumn 2017, I majored in Statistics at Bandung Islamic University. I learned a lot about Statistics. 
          Not only that, I develop myself by joining in Organization, Olympiad Team and Project, then participating in Competitions, and Intern. 
          All of that, so that I can do time management and collaboration, then can know and learn about Machine Learning, Data Analyst, Data Science, and Data Engineer.`,
          `My main Hobby is Coding. I love Coding, because I think the first step to being able to solve the problem is to get used to Coding.`
        ]
      }
    ],
    {
      experience: {
        title: "My Experience"
      }
    }
  ],
  social: [
    {icon: <TwitterOutlined />,link: "https://twitter.com/adityaadamf"},
    {icon: <LinkedinFilled />,link: "https://www.linkedin.com/in/adityaadamf/"},
    {icon: <GithubOutlined />,link: "https://github.com/adityaadamf"},
    {icon: <MailOutlined />,link: "mailto:itsadityaadam@gmail.com"}
  ]
}

export default function AdityaBody() {
  return <Content className="AdityaContent" />;
}

export function Home() {
  const [myPortfolio, setMyPortfolio] = useState([]),
        [mySkills, setMySkills] = useState([]),
        [widthHeader, setwidthHeader] = useState(window.innerWidth);

  useEffect(() => {
    const fetchData = async () => {
      await Promise.all([
        fetch('/data/portfolio.json').then(res => res.json()),
        fetch('/data/skills.json').then(res => res.json())
      ]).then(data => {
        setMyPortfolio(data[0].portfolio)
        setMySkills(data[1].skills)
      });
    };

    const handleResize = () => {
      setwidthHeader(window.innerWidth)
    }

    window.addEventListener('resize', handleResize)

    fetchData();
  }, [])

  return(
    <>
    <div className="AdityaHome">
      <div className="one">
        <Col span={(widthHeader > 900) ? 12 : 24} offset={(widthHeader > 900) ? 6 : 0} style={{ display: 'flex', marginBottom: 20 }}>
          <Avatar size={150} src={process.env.PUBLIC_URL + data.home[0][2]} />
        </Col>
        <Title level={2} style={{ margin: 0, textAlign: 'center' }}>{data.home[0][0]}</Title>
        <Paragraph style={{ fontSize: 18, textAlign: 'center' }}>{data.home[0][1]}</Paragraph>
        <Col span={(widthHeader > 900) ? 12 : 24} offset={(widthHeader > 900) ? 6 : 0} style={{ display: 'flex', marginBottom: 20 }}>
          <Space size="middle" style={{ margin: 'auto' }}>
            {data.social.map(item => 
              <Link className="social" href={item.link} target="_blank" style={{ fontSize: 30 }}>{item.icon}</Link>
            )}
          </Space>
        </Col>
        <Col span={(widthHeader > 900) ? 12 : 24} offset={(widthHeader > 900) ? 6 : 0} style={{ display: 'flex' }}>
          <Button className="buttonStyle" size="large" style={{ margin: 'auto' }} onClick={() => getPages('/portfolio',1)} >My Project</Button>
        </Col>
      </div>
      <div className="two">
        <Title level={2}>{data.home[1].personal[0]}</Title>
        <Paragraph className="paragraphStyle">{data.home[1].personal[1]}</Paragraph>
        <Button className="buttonStyle" size="large" style={{ margin: 'auto' }} onClick={() => getPages('/about',1)} >More About Me</Button>
      </div>
      <div className="three">
        <Title level={2} style={{ textAlign: 'center', marginBottom: 25 }}>{data.home[2].skills.title}</Title>
        <Row gutter={[16, 24]}>
          {mySkills.map(item => 
            <Col span={(widthHeader > 900) ? 8 : (widthHeader > 500) ? 12 : 24}>
              <Card className="cardStyle" size="small" title={item.name} bordered={false}>
                {item.point.join(', ')}
              </Card>
            </Col>
          )}
        </Row>
      </div>
      <div className="four">
        <Title level={2}>{data.home[3].activity.title}</Title>
        <List
          itemLayout="horizontal"
          dataSource={myPortfolio}
          renderItem={item => (
            <List.Item className="activityStyle">
              <List.Item.Meta
                title={<Link onClick={(e) => item.href.length > 0 ? window.open(item.href,"_blank") : e.preventDefault()}>{item.title} ({item.date})</Link>}
                description={item.content}
              />
            </List.Item>
          )}
        />
      </div>
    </div>
    </>
  )
}

export function About() {
  const [widthHeader, setwidthHeader] = useState(window.innerWidth),
        [myExperiences, setMyExperiences] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      await fetch('/data/experiences.json'
      ).then(response => response.json())
      .then(data => {
        setMyExperiences(data.experience)
      });
    };

    fetchData();

    const handleResize = () => {
      setwidthHeader(window.innerWidth)
    }

    window.addEventListener('resize', handleResize)
  }, [])

  return(
    <>
    <div className="AdityaAbout">
      <Breadcrumb>
        <Breadcrumb.Item href="/">
          <HomeOutlined />
        </Breadcrumb.Item>
        <Breadcrumb.Item>About Me</Breadcrumb.Item>
      </Breadcrumb>
      <div className="one">
        <Row>
          <Col span={(widthHeader < 1500) ? 5 : 4}>
            <Avatar shape="square" src={process.env.PUBLIC_URL + data.about[0][1]} />
          </Col>
          <Col span={(widthHeader < 1500) ? 19 : 20}>
            <Title level={2}>{data.about[0][0]}</Title>
            {data.about[0][2].desc.map((item,i) => 
              <Paragraph>
                {item}
              </Paragraph>
            )}
          </Col>
        </Row>
        <Row>
          <Space size="middle" style={{ margin: 'auto' }}>
            {data.social.map(item => 
              <Link className="social" href={item.link} target="_blank" style={{ fontSize: 30 }}>{item.icon}</Link>
            )}
          </Space>
        </Row>
      </div>
      <div className="two">
        <Title level={2} style={{ textAlign: 'center', marginBottom: 50 }}>{data.about[1].experience.title}</Title>
        <Timeline mode={(widthHeader > 900) ? "alternate" : "left"}>
        {myExperiences.map(item => 
          <Timeline.Item color="grey">
            <Card className="cardStyleTimeline" size="small" title={item.title} bordered={false}>
              <Title level={5}>{item.company}</Title>
              <Paragraph>{item.desc}</Paragraph>
              <Paragraph>{item.date}</Paragraph>
            </Card>
          </Timeline.Item>
        )}
        </Timeline>
      </div>
    </div>
    </>
  )
}

export function Portfolio() {
  const [myPortfolio, setMyPortfolio] = useState([])

  useEffect(() => {
    const fetchData = async () => {
      await fetch('/data/portfolio.json'
      ).then(response => response.json())
      .then(data => {
        setMyPortfolio(data.portfolio)
      });
    };

    fetchData();
  }, [])

  return(
    <>
    <div className="AdityaPortfolio">
      <Breadcrumb>
        <Breadcrumb.Item href="/">
          <HomeOutlined />
        </Breadcrumb.Item>
        <Breadcrumb.Item>Portfolio</Breadcrumb.Item>
      </Breadcrumb>
      <div className="one">
        <List
          itemLayout="vertical"
          size="large"
          dataSource={myPortfolio}
          renderItem={item => (
            <List.Item
              key={item.title}
              extra={
                <img
                  alt="logo"
                  src={item.image}
                />
              }
            >
              <List.Item.Meta
                title={<Link onClick={(e) => item.href.length > 0 ? window.open(item.href,"_blank") : e.preventDefault()}>{item.title}</Link>}
                description={item.date}
              />
              {item.content}
            </List.Item>
          )}
        />
      </div>
    </div>
    </>
  )
}

export function NotFound() {
  return(
    <Result
      status="404"
      title="404"
      subTitle="Sorry, the page you visited does not exist."
      extra={<Button type="link" href="/">Back Home</Button>}
    />
  )
}