import React, { useEffect, useState } from "react";
import { Layout, Menu, Typography, 
         Affix, Dropdown, Button } from 'antd';
import { AppstoreOutlined } from '@ant-design/icons';

const { Header } = Layout,
      { Title, Link } = Typography;

export default function AdityaHeader() {
  const [headers, setHeader] = useState([]),
        [widthHeader, setwidthHeader] = useState(window.innerWidth);

  useEffect(() => {
    const getData = async () => {
      await fetch('/data/header.json')
      .then(res => res.json())
      .then(result => {
        setHeader(result.header);
      });
    };

    const handleResize = () => {
      setwidthHeader(window.innerWidth)
    }

    window.addEventListener('resize', handleResize)

    getData();

  }, [window.innerWidth]);

  return(
    <Affix offsetTop={0}>
      <Header className="light">
        <Link href="/">
          <div className="logo">
            <Title level={3}>Aditya Adam F.</Title>
          </div>
        </Link>
        {widthHeader > 900 ?
          <Menu 
            theme="light" 
            mode="horizontal" 
            defaultSelectedKeys={[
              (window.location.pathname === '/') ? 'home' : window.location.pathname.substring(1)
            ]}>
            {headers.map(item =>
              <Menu.Item key={item.key} ><Link href={item.link} target={item.target}>{item.name}</Link></Menu.Item>
            )}
          </Menu>
        :
          <Dropdown 
             placement="bottomCenter"
            overlay={
              <Menu>
                {headers.map(item =>
                  <Menu.Item key={item.key} ><Link href={item.link} target={item.target}>{item.name}</Link></Menu.Item>
                )}
              </Menu>
            } 
            trigger={['click']}
          >
            <Button className="ant-dropdown-link" type="text" onClick={e => e.preventDefault()}>
              <AppstoreOutlined />
            </Button>
          </Dropdown>
        }
      </Header>
    </Affix>
  );
}